    H.append('<button class="bs" onclick="fn_save()">\uC800\uC7A5 &#x2193;</button></div></div></div></div>')
    H.append('<script>')
    H.append('const IT='+IT+';')
    H.append('const LC='+LC+';')
    H.append('let pg=0,ds="",lo="",sigCanvas,sigCtx,drawing=false;')
    H.append('window.onload=function(){sigCanvas=document.getElementById("sig");sigCtx=sigCanvas.getContext("2d");sigCtx.strokeStyle="#222";sigCtx.lineWidth=2;sigCtx.lineCap="round";sigCanvas.addEventListener("mousedown",function(e){drawing=true;sigCtx.beginPath();sigCtx.moveTo(e.offsetX,e.offsetY)});sigCanvas.addEventListener("mousemove",function(e){if(!drawing)return;sigCtx.lineTo(e.offsetX,e.offsetY);sigCtx.stroke()});sigCanvas.addEventListener("mouseup",function(){drawing=false});};')
